"""Tests for --log-file CLI arg and excepthook wiring."""

import logging
import sys
from unittest import mock

from claude_dashboard.__main__ import _install_excepthook


class TestInstallExcepthook:
    def test_uncaught_exception_logged_as_critical(self):
        test_logger = logging.getLogger("test.excepthook")
        _install_excepthook(logger=test_logger)

        try:
            raise RuntimeError("boom")
        except RuntimeError:
            exc_type, exc_value, exc_tb = sys.exc_info()

        with mock.patch.object(test_logger, "critical") as mock_critical:
            sys.excepthook(exc_type, exc_value, exc_tb)

        mock_critical.assert_called_once()
        args, kwargs = mock_critical.call_args
        assert args[0] == "uncaught exception"
        assert kwargs["exc_info"][0] is RuntimeError

    def test_keyboard_interrupt_uses_default_hook(self):
        test_logger = logging.getLogger("test.excepthook")
        _install_excepthook(logger=test_logger)

        try:
            raise KeyboardInterrupt()
        except KeyboardInterrupt:
            exc_type, exc_value, exc_tb = sys.exc_info()

        with (
            mock.patch.object(test_logger, "critical") as mock_critical,
            mock.patch("sys.__excepthook__") as mock_default,
        ):
            sys.excepthook(exc_type, exc_value, exc_tb)

        mock_critical.assert_not_called()
        mock_default.assert_called_once_with(exc_type, exc_value, exc_tb)
